import React from "react";
import { Form } from "react-bootstrap";
import DatePicker from "react-datepicker";
import "react-datepicker/dist/react-datepicker.css";

function SchemeMastersForm({ module }) {
    
  return (
   <div className="card">
      <div className="card-header d-flex justify-content-between border-0" style={{background: module.bg,borderLeft: `5px solid ${module.color}`
            }}>
         <div className="header-title">
            <h5 className="card-title">Add Scheme Type</h5>
            <small className="sub">Fill in the details below and save to add a new </small>
         </div>
      </div>
      <div className="card-body" style={{minHeight:"600px"}}>
         <div className="new-user-info">
            <Form>
               <div className="row">
                  <div className="form-group col-md-6">
                     <label className="form-label col-form-label col-form-label-sm" htmlFor="fname">Scheme Type <span style={{color: "Red"}}>*</span></label>
                     <input type="text" className={`form-control form-control-sm`} id="tbempcode" placeholder="Scheme Type"/>
                  </div>
                  <div className="form-group col-md-6">
                     <label className="form-label col-form-label col-form-label-sm" htmlFor="fname">Scheme Type(Local) 
                        <span style={{color: "Red"}}>*</span></label>
                     <input type="text" className={`form-control form-control-sm`} id="tbempcode" placeholder="Scheme Type(Local)"/>
                  </div>
                  <div className="text-right">
                     <button type="submit" className="btn btn-primary"><i className="fa fa-check"></i> Save</button>&nbsp;&nbsp;
                     <button type="button" className="btn btn-danger"><i className="fa fa-times"></i> Cancel </button>
                  </div>
               </div>
            </Form>
         </div>
      </div>
   </div>
  );
}

export default SchemeMastersForm;
